/**
 * Vitest Integration Test Configuration
 *
 * Configuration for running integration tests that involve
 * database operations and service interactions.
 *
 * @module vitest.integration.config
 */

import { defineConfig } from 'vitest/config';
import { resolve } from 'path';

export default defineConfig({
  test: {
    // Test environment
    environment: 'node',

    // Global test setup
    globals: true,

    // Test file patterns - only include integration tests
    include: ['**/*.integration.spec.{js,ts}', 'tests/integration/**/*.spec.{js,ts}'],
    exclude: ['**/node_modules/**', '**/dist/**', '**/coverage/**'],

    // Longer timeouts for integration tests
    testTimeout: 30000,
    hookTimeout: 30000,

    // Run tests sequentially to avoid database conflicts
    sequence: {
      shuffle: false,
    },

    // Pool configuration for integration tests
    pool: 'forks',
    poolOptions: {
      forks: {
        singleFork: true,
      },
    },

    // Coverage configuration
    coverage: {
      provider: 'v8',
      reporter: ['text', 'json', 'html'],
      exclude: [
        'node_modules/**',
        'dist/**',
        '**/*.d.ts',
        '**/*.spec.ts',
        '**/*.test.ts',
        '**/index.ts',
        'coverage/**',
        'prisma/**',
        'scripts/**',
      ],
    },

    // Mock configuration
    mockReset: true,
    restoreMocks: true,

    // Setup files for integration tests
    setupFiles: ['./tests/integration/setup.ts'],
  },

  // Path aliases (must match tsconfig.json)
  resolve: {
    alias: {
      '@': resolve(__dirname, './src'),
    },
  },
});
